def compute(inputs):
    cash_flows = inputs["cash_flows"]
    discount_rate = inputs["discount_rate"]

    if not isinstance(cash_flows, list):
        raise TypeError("Cash flows must be a list.")
    if not all(isinstance(cf, (int, float)) for cf in cash_flows):
        raise ValueError("All cash flow values must be numbers.")
    if not isinstance(discount_rate, (int, float)):
        raise TypeError("Discount rate must be a number.")

    # Discount rate must be greater than -1.
    if discount_rate <= -1:
        raise ValueError("Discount rate must be greater than -1.")

    # Calculate NPV using the formula: NPV = Sum(CF_t / (1 + r)^t)
    # where t is the period index starting from 0 for the initial investment (cash_flows[0]).
    npv = sum(cf / ((1 + discount_rate) ** i) for i, cf in enumerate(cash_flows))

    return {"npv": npv}

